import { ref, computed, watch, nextTick, reactive, onBeforeUnmount, inject, onMounted } from 'vue-demi';
import { getElById, getNodePath, replaceChildNode, isPage, isDslNode, toLine } from '@tmagic/core';

const useEditorDsl = (app, win = window) => {
  const root = ref();
  const curPageId = ref();
  const selectedId = ref();
  const pageConfig = computed(
    () => root.value?.items?.find((item) => item.id === curPageId.value) || root.value?.items?.[0]
  );
  watch(pageConfig, async () => {
    await nextTick();
    const page = document.querySelector(".magic-ui-page");
    page && win.magic?.onPageElUpdate(page);
  });
  win.magic?.onRuntimeReady({
    getApp() {
      return app;
    },
    updateRootConfig(config) {
      root.value = config;
      if (typeof curPageId.value === "undefined") {
        curPageId.value = config.items?.[0]?.id;
      }
      if (typeof selectedId.value === "undefined") {
        selectedId.value = curPageId.value;
      }
      app?.setConfig(config, curPageId.value);
    },
    updatePageId(id) {
      curPageId.value = id;
      app?.setPage(id);
    },
    select(id) {
      selectedId.value = id;
      if (app?.getPage(id)) {
        this.updatePageId?.(id);
      }
      const el = getElById()(document, `${id}`);
      if (el) return el;
      return nextTick().then(() => getElById()(document, `${id}`));
    },
    add({ config, parentId }) {
      if (!root.value) throw new Error("error");
      if (!selectedId.value) throw new Error("error");
      if (!parentId) throw new Error("error");
      const parent = getNodePath(parentId, [root.value]).pop();
      if (!parent) throw new Error("未找到父节点");
      if (config.type !== "page") {
        const parentNode = app?.page?.getNode(parent.id);
        parentNode && app?.page?.initNode(config, parentNode);
      }
      if (parent.id !== selectedId.value) {
        const index = parent.items?.findIndex((child) => child.id === selectedId.value);
        parent.items?.splice(index + 1, 0, config);
      } else {
        parent.items?.push(config);
      }
    },
    update({ config, parentId }) {
      if (!root.value || !app) throw new Error("error");
      const newNode = app.dataSourceManager?.compiledNode(config, undefined, true) || config;
      replaceChildNode(reactive(newNode), [root.value], parentId);
      const nodeInstance = app.getNode(config.id);
      if (nodeInstance) {
        nodeInstance.setData(newNode);
      }
      if (app.page?.data.id === config.id) {
        app.page.setData(newNode);
      }
    },
    remove({ id, parentId }) {
      if (!root.value) throw new Error("error");
      const node = getNodePath(id, [root.value]).pop();
      if (!node) throw new Error("未找到目标元素");
      const parent = getNodePath(parentId, [root.value]).pop();
      if (!parent) throw new Error("未找到父元素");
      if (node.type === "page") {
        app?.deletePage();
      } else {
        app?.page?.deleteNode(node.id);
      }
      const index = parent.items?.findIndex((child) => child.id === node.id);
      parent.items.splice(index, 1);
    }
  });
  return {
    pageConfig
  };
};

const useDsl = (app) => {
  const pageConfig = ref(app?.page?.data || {});
  const updateDataHandler = (nodes, sourceId, changeEvent) => {
    nodes.forEach((node) => {
      if (isPage(node)) {
        pageConfig.value = node;
      } else {
        replaceChildNode(reactive(node), [pageConfig.value]);
      }
    });
    if (!app) return;
    nextTick(() => {
      app.emit("replaced-node", { nodes, sourceId, ...changeEvent });
    });
  };
  app?.dataSourceManager?.on("update-data", updateDataHandler);
  onBeforeUnmount(() => {
    app?.dataSourceManager?.off("update-data", updateDataHandler);
  });
  return {
    pageConfig
  };
};

const useApp = ({ methods = {}, config, iteratorContainerId, iteratorIndex }) => {
  const app = inject("app");
  const emitData = {
    config,
    ...methods
  };
  const display = (config2) => {
    if (config2.visible === false) return false;
    if (config2.condResult === false) return false;
    const displayCfg = config2.display;
    if (typeof displayCfg === "function") {
      return displayCfg(app);
    }
    return displayCfg !== false;
  };
  const node = isDslNode(config) && config.id ? app?.getNode(config.id, iteratorContainerId, iteratorIndex) : undefined;
  if (node) {
    node.emit("created", emitData);
    onMounted(() => {
      node.emit("mounted", emitData);
    });
    onBeforeUnmount(() => {
      node.emit("destroy", emitData);
    });
  }
  return {
    app,
    node,
    display
  };
};

function useComponent(options = "") {
  let componentType;
  let app;
  let component;
  if (typeof options === "string") {
    componentType = options;
  } else {
    ({ componentType, app } = options);
  }
  if (!componentType || componentType === "") {
    componentType = "container";
  }
  if (!app) {
    app = inject("app");
  }
  component = resolveComponent({ componentType, app });
  if (!component && !componentType.startsWith("magic-ui-")) {
    componentType = `magic-ui-${toLine(componentType)}`;
    component = resolveComponent({ componentType, app });
  }
  return component ?? componentType;
}
function resolveComponent({ componentType, app }) {
  return app?.resolveComponent(componentType);
}

export { useApp, useComponent, useDsl, useEditorDsl };
